SELECT 
 	  COUNT(*) AS CNT
FROM SAO_OTP_CHARGE 
WHERE USER_ID = #{userId} 
 AND DEVICE_ID = #{deviceId}

mapper.update:
UPDATE SAO_OTP_CHARGE 
SET DEVICE_ID = #{deviceId} 
  , DEVICE_TYPE = #{deviceType} 
  , ISSUE_TYPE = #{issueType} 
  , TOKEN_ID = #{tokenId} 
  , REG_DEVICE_UUID = #{regDeviceUuid}
  , USER_REG_DT = CURRENT TIMESTAMP 
WHERE USER_ID = #{userId}
